import{_ as t,o as n,c as o,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"13. Best Practice Employment Commitment","description":"","frontmatter":{"title":"13. Best Practice Employment Commitment","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["union-matters"]},"headers":[],"relativePath":"ebas/mspp/disputes/13-best-practice-employment-commitment.md","filePath":"ebas/mspp/disputes/13-best-practice-employment-commitment.md"}'),i={name:"ebas/mspp/disputes/13-best-practice-employment-commitment.md"};function r(a,e,m,p,c,l){return n(),o("div",null,[...e[0]||(e[0]=[s('<h1 id="_13-best-practice-employment-commitment" tabindex="-1">13. Best Practice Employment Commitment <a class="header-anchor" href="#_13-best-practice-employment-commitment" aria-label="Permalink to &quot;13. Best Practice Employment Commitment&quot;">​</a></h1><p><strong>a.</strong> The parties agree to establish a committee to discuss Best Practice Employment Commitments (BPEC) during the life of the Agreement.</p><p><strong>b.</strong> The Committee will comprise nominated representatives from the Union, the VHIA and Department of Health (as required). The Committee may, by agreement, establish sub-groups or delegate individual matters to a relevant health service(s) as required and will meet on matters including:</p><p><strong>(i)</strong> implementation of the Agreement;</p><p><strong>(ii)</strong> climate change initiatives to reduce carbon and other harmful emissions within the public health system including: <strong>(A)</strong> discussion regarding the environmental performance of Employers published in accordance with the Department’s environmental guidelines, <strong>(B)</strong> discussion regarding any reports or activities of other bodies such as Global Green and Healthy Hospitals that are relevant to the reduction of carbon emissions, <strong>(C)</strong> promotion of initiatives taken by an Employer and / or Employees to reduce carbon and other harmful emissions and where appropriate the Union and the VHIA may jointly make recommendation to the Minister in relation to adopting sector wide initiatives; <strong>(D)</strong> invite external interest groups, unions or other organisations to discuss the impacts the public health system as a whole has on producing harmful emissions and any initiatives to reduce these.</p><p><strong>c.</strong> working from home, including emerging standards;</p><p><strong>d.</strong> implementation of a best practice guide to address emerging equity issues arising from flexible working arrangements;</p><p><strong>e.</strong> any legislative requirement to undertake gender equity activities;</p><p><strong>f.</strong> consolidation of major agreement provisions to reduce complexity and inefficiencies within the public health system;</p><p><strong>g.</strong> template change impact statements</p><p><strong>h.</strong> the development of an assessment measure for workload stress; and</p><p><strong>i.</strong> measures to support and improve understanding of and compliance with this Agreement.</p><p><strong>j.</strong> explore the development of a clinical governance structure for psychology services.</p><p><strong>k.</strong> As part of the new Agreement, the parties have agreed to preference secure modes of employment over insecure modes of employment. In that regard, Employers may need to review existing supplementary labour to support secure modes of employment, including the establishment of casual relief banks. In conducting that review, Employers are to report through clause 17.10, the steps in which it will take to ensure supplementary labour is sufficient to support the preference of secure modes of employment.</p><p><strong>l.</strong> The Committee will schedule a minimum of six meetings per year.</p><p>Plain language terms: best practice.</p>',16)])])}const h=t(i,[["render",r]]);export{d as __pageData,h as default};
